<?php $it=$item??['id'=>'','name'=>'','quantity'=>1,'unit'=>'Stk','category'=>'','location_id'=>'','container_id'=>'','location_detail'=>'','notes'=>'','tags'=>[]]; ?><h2><?= $it['id']?'Artikel bearbeiten':'Artikel anlegen' ?></h2><form method="post" action="?p=save_item" class="form"><?=csrf_field()?><input type="hidden" name="id" value="<?=h($it['id'])?>"><label>Name *<input required name="name" value="<?=h($it['name'])?>"></label><label>Menge *<input required type="number" step="0.001" name="quantity" value="<?=h($it['quantity'])?>"></label><label>Einheit *<input required name="unit" value="<?=h($it['unit'])?>"></label><label>Kategorie<input name="category" value="<?=h($it['category'])?>"></label><label>Ort *<select required name="location_id"><?php foreach($locations as $l):?><option value="<?=h($l['id'])?>" <?=$it['location_id']==$l['id']?'selected':''?>><?=h($l['code'].' '.$l['name'])?></option><?php endforeach?></select></label><label>Behälter<select name="container_id"><option value="">Kein Behälter</option><?php foreach($containers as $c):?><option value="<?=h($c['id'])?>" <?=$it['container_id']==$c['id']?'selected':''?>><?=h($c['code'].' '.$c['name'].' @ '.$c['location_code'])?></option><?php endforeach?></select></label><label>Detail<input name="location_detail" value="<?=h($it['location_detail'])?>"></label><label>Tags<input name="tags" value="<?=h(tags_to_string($it['tags']))?>"></label><label>Notizen<textarea name="notes"><?=h($it['notes'])?></textarea></label><button>Speichern</button><a class="button" href="?p=items">Zurück</a></form><?php if($it['id']):?><form method="post" action="?p=delete_item" onsubmit="return confirm('Artikel wirklich löschen?')"><?=csrf_field()?><input type="hidden" name="id" value="<?=h($it['id'])?>"><button class="danger">Löschen</button></form><?php endif?>
